def _find_libreoffice():
    """Find the LibreOffice executable on the system."""
    
    # Common executable names
    executables = ['libreoffice', 'soffice', 'lowriter']
    
    # Check if any are in PATH
    for exe in executables:
        path = shutil.which(exe)
        if path:
            return path
    
    # Platform-specific common installation paths
    if sys.platform == 'win32':
        common_paths = [
            r'C:\Program Files\LibreOffice\program\soffice.exe',
            r'C:\Program Files (x86)\LibreOffice\program\soffice.exe',
            r'C:\Program Files\LibreOffice\program\soffice.com',
            r'C:\Program Files (x86)\LibreOffice\program\soffice.com',
        ]
        # Also check for versioned installations
        for base in [r'C:\Program Files', r'C:\Program Files (x86)']:
            base_path = Path(base)
            if base_path.exists():
                for item in base_path.iterdir():
                    if 'libreoffice' in item.name.lower():
                        soffice = item / 'program' / 'soffice.exe'
                        if soffice.exists():
                            common_paths.append(str(soffice))
    elif sys.platform == 'darwin':
        common_paths = [
            '/Applications/LibreOffice.app/Contents/MacOS/soffice',
            os.path.expanduser('~/Applications/LibreOffice.app/Contents/MacOS/soffice'),
        ]
    else:  # Linux and other Unix-like
        common_paths = [
            '/usr/bin/libreoffice',
            '/usr/bin/soffice',
            '/usr/local/bin/libreoffice',
            '/usr/local/bin/soffice',
            '/snap/bin/libreoffice',
            '/opt/libreoffice/program/soffice',
        ]
        # Check for versioned installations
        for item in Path('/opt').iterdir() if Path('/opt').exists() else []:
            if 'libreoffice' in item.name.lower():
                soffice = item / 'program' / 'soffice'
                if soffice.exists():
                    common_paths.append(str(soffice))
    
    for path in common_paths:
        if os.path.isfile(path) and os.access(path, os.X_OK):
            return path
    
    return None


def _get_libreoffice_filter(output_format, input_extension):
    """
    Get the appropriate LibreOffice filter name for specific conversions.
    
    Returns None if the default filter should be used.
    """
    
    # Image output filters
    image_filters = {
        'png': 'png',
        'jpg': 'jpg',
        'jpeg': 'jpg',
        'bmp': 'bmp',
        'tiff': 'tiff',
        'svg': 'svg',
    }
    
    # Document-specific filters
    if output_format == 'pdf':
        # PDF filter depends on input type
        if input_extension in ['.pptx', '.ppt', '.odp']:
            return 'impress_pdf_Export'
        elif input_extension in ['.xlsx', '.xls', '.ods', '.csv']:
            return 'calc_pdf_Export'
        elif input_extension in ['.png', '.jpg', '.jpeg', '.bmp', '.tiff', '.tif', '.gif', '.svg']:
            return 'draw_pdf_Export'
        else:
            return 'writer_pdf_Export'
    
    elif output_format == 'docx':
        return 'MS Word 2007 XML'
    
    elif output_format == 'doc':
        return 'MS Word 97'
    
    elif output_format == 'xlsx':
        return 'Calc MS Excel 2007 XML'
    
    elif output_format == 'xls':
        return 'MS Excel 97'
    
    elif output_format == 'pptx':
        return 'Impress MS PowerPoint 2007 XML'
    
    elif output_format == 'ppt':
        return 'MS PowerPoint 97'
    
    elif output_format == 'rtf':
        return 'Rich Text Format'
    
    elif output_format in image_filters:
        # For image output from presentations
        if input_extension in ['.pptx', '.ppt', '.odp']:
            return None  # Let LibreOffice figure it out
        return None
    
    return None


def _find_converted_file(directory, original_stem, expected_format):
    """
    Find the converted file in the output directory.
    
    LibreOffice names the output file based on the input filename stem
    with the new extension.
    """
    
    dir_path = Path(directory)
    
    # Map format to possible extensions
    format_extensions = {
        'pdf': ['.pdf'],
        'docx': ['.docx'],
        'doc': ['.doc'],
        'odt': ['.odt'],
        'xlsx': ['.xlsx'],
        'xls': ['.xls'],
        'ods': ['.ods'],
        'pptx': ['.pptx'],
        'ppt': ['.ppt'],
        'odp': ['.odp'],
        'html': ['.html', '.htm'],
        'txt': ['.txt'],
        'csv': ['.csv'],
        'png': ['.png'],
        'jpg': ['.jpg', '.jpeg'],
        'bmp': ['.bmp'],
        'tiff': ['.tiff', '.tif'],
        'svg': ['.svg'],
        'rtf': ['.rtf'],
        'xml': ['.xml'],
        'epub': ['.epub'],
    }
    
    extensions = format_extensions.get(expected_format, [f'.{expected_format}'])
    
    # First, try exact match with original stem
    for ext in extensions:
        candidate = dir_path / f"{original_stem}{ext}"
        if candidate.exists():
            return candidate
    
    # If not found, look for any file with the expected extension
    for ext in extensions:
        for f in dir_path.glob(f"*{ext}"):
            if f.is_file():
                return f
    
    # Last resort: return any file in the directory
    for f in dir_path.iterdir():
        if f.is_file():
            return f
    
    return None


def batch_convert(input_files, output_dir, output_format):
    """
    Convert multiple files to the specified format.
    
    Args:
        input_files (list): List of input file paths
        output_dir (str): Directory for output files
        output_format (str): Target format
    
    Returns:
        list: List of result dictionaries for each conversion
    """
    results = []
    output_dir_path = Path(output_dir)
    output_dir_path.mkdir(parents=True, exist_ok=True)
    
    for input_file in input_files:
        input_path = Path(input_file)
        output_file = output_dir_path / f"{input_path.stem}.{output_format}"
        result = convertDocument(input_file, str(output_file), output_format)
        result['input_file'] = input_file
        results.append(result)
    
    return results


